@namespace sv_b6afd53599bc43c58dcc968f2c2a7800.Components.JobApplication

<nav class="step-indicator mb-4" aria-label="Application steps">
    <ol class="d-flex list-unstyled justify-content-between position-relative step-list">
        @for (int i = 0; i < StepNames.Length; i++)
        {
            var step = i + 1;
            var isCompleted = CompletedSteps.Contains(step);
            var isCurrent = step == CurrentStep;
            var isFuture = step > CurrentStep && !isCompleted;
            var cssClass = isCurrent ? "active" : isCompleted ? "completed" : "dimmed";

            <li class="step-item text-center @cssClass">
                @if (isCompleted && !isCurrent)
                {
                    <button type="button" class="btn btn-link step-btn p-0" @onclick="() => OnStepClicked.InvokeAsync(step)">
                        <span class="step-circle">
                            <span>&#10003;</span>
                        </span>
                        <span class="step-label d-block mt-1">@StepNames[step - 1]</span>
                    </button>
                }
                else
                {
                    <div class="step-btn p-0">
                        <span class="step-circle">
                            <span>@step</span>
                        </span>
                        <span class="step-label d-block mt-1">@StepNames[step - 1]</span>
                    </div>
                }
            </li>
        }
    </ol>
</nav>

@code {
    private static readonly string[] StepNames =
    {
        "Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"
    };

    [Parameter, EditorRequired] public int CurrentStep { get; set; }
    [Parameter, EditorRequired] public HashSet<int> CompletedSteps { get; set; } = new();
    [Parameter] public EventCallback<int> OnStepClicked { get; set; }
}

.step-indicator .step-list {
    counter-reset: step;
    gap: 0.25rem;
}

.step-item {
    flex: 1;
    position: relative;
}

.step-item + .step-item::before {
    content: "";
    position: absolute;
    top: 18px;
    left: -50%;
    width: 100%;
    height: 2px;
    background: #dee2e6;
    z-index: 0;
}

.step-item.completed + .step-item::before,
.step-item.active + .step-item::before {
    background: #0d6efd;
}

.step-circle {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    width: 36px;
    height: 36px;
    border-radius: 50%;
    background: #dee2e6;
    color: #6c757d;
    font-weight: 600;
    font-size: 0.875rem;
    position: relative;
    z-index: 1;
}

.step-item.active .step-circle {
    background: #0d6efd;
    color: #fff;
}

.step-item.completed .step-circle {
    background: #198754;
    color: #fff;
}

.step-item.dimmed .step-label {
    color: #adb5bd;
}

.step-item.active .step-label {
    color: #0d6efd;
    font-weight: 600;
}

.step-item.completed .step-label {
    color: #198754;
}

.step-label {
    font-size: 0.8rem;
}

.step-btn {
    background: none;
    border: none;
    text-decoration: none;
    cursor: default;
}

button.step-btn {
    cursor: pointer;
}

button.step-btn:hover .step-circle {
    box-shadow: 0 0 0 3px rgba(25, 135, 84, 0.25);
}

@namespace sv_b6afd53599bc43c58dcc968f2c2a7800.Components.JobApplication

<div class="card mb-3">
    <div class="card-body">
        @if (CanRemove)
        {
            <div class="d-flex justify-content-between align-items-start">
                <h6 class="card-title">Position @(Index + 1)</h6>
                <button type="button" class="btn btn-outline-danger btn-sm" @onclick="() => OnRemove.InvokeAsync()">Remove</button>
            </div>
        }
        else
        {
            <h6 class="card-title">Position @(Index + 1)</h6>
        }

        <div class="row g-3 mt-1">
            <div class="col-md-6">
                <label class="form-label">Company Name <span class="text-danger">*</span></label>
                <input type="text" class="form-control" @bind="Entry.Company" />
            </div>
            <div class="col-md-6">
                <label class="form-label">Job Title <span class="text-danger">*</span></label>
                <input type="text" class="form-control" @bind="Entry.Title" />
            </div>
            <div class="col-md-4">
                <label class="form-label">Start Date <span class="text-danger">*</span></label>
                <input type="date" class="form-control" @bind="Entry.StartDate" />
            </div>
            <div class="col-md-4">
                <label class="form-label">End Date</label>
                <input type="date" class="form-control" disabled="@Entry.IsCurrent" @bind="Entry.EndDate" />
            </div>
            <div class="col-md-4 d-flex align-items-end">
                <div class="form-check mb-2">
                    <input type="checkbox" class="form-check-input" id="current-@Index" @bind="Entry.IsCurrent"
                           @bind:after="OnCurrentChanged" />
                    <label class="form-check-label" for="current-@Index">Currently working here</label>
                </div>
            </div>
            <div class="col-12">
                <label class="form-label">Description</label>
                <textarea class="form-control" rows="3" @bind="Entry.Description"></textarea>
            </div>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public WorkEntryModel Entry { get; set; } = default!;
