@page "/apply"
@rendermode InteractiveServer
@using sv_b6afd53599bc43c58dcc968f2c2a7800.Components.JobApplication
@inject IApplicationService ApplicationService

<PageTitle>Job Application</PageTitle>

<div class="container py-4" style="max-width: 800px;">
    <h2 class="mb-4">Job Application</h2>

    <StepIndicator CurrentStep="currentStep"
                   CompletedSteps="completedSteps"
                   OnStepClicked="GoToStep" />

    @switch (currentStep)
    {
        case 1:
            <PersonalInfoStep Model="personalInfo"
                              ApplicationService="ApplicationService"
                              OnNext="NextStep" />
            break;

        case 2:
            <WorkHistoryStep Entries="workEntries"
                             OnNext="NextStep"
                             OnBack="PreviousStep" />
            break;

        case 3:
            <ReferencesStep References="references"
                            OnNext="NextStep"
                            OnBack="PreviousStep" />
            break;

        case 4:
            <CoverLetterStep @bind-CoverLetter="coverLetter"
                             OnNext="NextStep"
                             OnBack="PreviousStep" />
            break;

        case 5:
            <ReviewStep Personal="personalInfo"
                        WorkEntries="workEntries"
                        References="references"
                        CoverLetter="@coverLetter"
                        IsSubmitted="isSubmitted"
                        ApplicationId="applicationId"
                        OnEdit="GoToStep"
                        OnBack="PreviousStep"
                        OnSubmit="SubmitApplication" />
            break;
    }
</div>

@code {
    private int currentStep = 1;
    private HashSet<int> completedSteps = new();
    private bool isSubmitted;
    private int? applicationId;

    // Form state
    private PersonalInfoModel personalInfo = new();
    private List<WorkEntryModel> workEntries = new() { new WorkEntryModel() };
    private List<ReferenceModel> references = new() { new ReferenceModel(), new ReferenceModel() };
    private string coverLetter = "";

    private void NextStep()
    {
        completedSteps.Add(currentStep);
        currentStep++;
    }

    private void PreviousStep()
    {
        if (currentStep > 1) currentStep--;
    }

    private void GoToStep(int step)
    {
        if (completedSteps.Contains(step) || step == currentStep)
        {
            currentStep = step;
        }
    }

    private async Task SubmitApplication()
    {
        var application = new JobApplication(
            new PersonalInfo(personalInfo.FullName, personalInfo.Email, personalInfo.Phone, personalInfo.Address),
            new WorkHistory(workEntries.Select(e => new WorkEntry(
                e.Company, e.Title, e.StartDate ?? DateTime.MinValue, e.IsCurrent ? null : e.EndDate, e.Description
            )).ToList()),
            references.Select(r => new Reference(r.Name, r.Relationship, r.Email, r.Phone)).ToList(),
            coverLetter
        );

        applicationId = await ApplicationService.SubmitApplicationAsync(application);
        isSubmitted = true;
    }
}

